/**
 * Webhook notification handler — fires HTTP callbacks when order events occur.
 *
 * Subscribes to EventBus events following the same pattern as
 * NotificationService and EmailNotificationHandler. External URLs can
 * be registered for specific event types, and webhook payloads are
 * dispatched when matching events fire.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventTypes: EventType[];
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  status: 'success' | 'failure';
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type WebhookHttpClient = (
  url: string,
  payload: WebhookPayload,
  secret?: string,
) => Promise<{ statusCode: number }>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

const defaultHttpClient: WebhookHttpClient = async (url, payload, _secret?) => {
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  return { statusCode: response.status };
};

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpClient: WebhookHttpClient;

  constructor(private eventBus: EventBus, httpClient?: WebhookHttpClient) {
    this.httpClient = httpClient ?? defaultHttpClient;
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.dispatchWebhooks('order:created', {
        event: 'order:created',
        timestamp: event.timestamp.toISOString(),
        data: {
          orderId: event.order.id,
          userId: event.order.userId,
          items: event.order.items,
          total: event.order.total,
          status: event.order.status,
        },
      });
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.dispatchWebhooks('order:status-changed', {
        event: 'order:status-changed',
        timestamp: event.timestamp.toISOString(),
        data: {
          orderId: event.order.id,
          userId: event.order.userId,
          previousStatus: event.previousStatus,
          newStatus: event.newStatus,
        },
      });
    });
  }

  /**
   * Register a webhook URL for specific event types.
   */
  register(params: {
    url: string;
    eventTypes: EventType[];
    secret?: string;
  }): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url: params.url,
      eventTypes: params.eventTypes,
      secret: params.secret,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(
      `Webhook registered: ${registration.id} for [${params.eventTypes.join(', ')}] -> ${params.url}`,
    );
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregister(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index < 0) return false;
    this.registrations.splice(index, 1);
    this.logger.info(`Webhook unregistered: ${webhookId}`);
    return true;
  }

  /**
   * Dispatch webhook payloads to all registered URLs matching the event type.
   */
  private async dispatchWebhooks(
    eventType: EventType,
    payload: WebhookPayload,
  ): Promise<void> {
    const matching = this.registrations.filter((r) =>
      r.eventTypes.includes(eventType),
    );

    for (const registration of matching) {
      const deliveryId = generateDeliveryId();
      try {
        const result = await this.httpClient(
          registration.url,
          payload,
          registration.secret,
        );
        this.deliveries.push({
          id: deliveryId,
          webhookId: registration.id,
          url: registration.url,
          eventType,
          payload,
          status: result.statusCode >= 200 && result.statusCode < 300 ? 'success' : 'failure',
          statusCode: result.statusCode,
          deliveredAt: new Date(),
        });
        this.logger.info(
          `Webhook delivered: ${deliveryId} to ${registration.url} (${result.statusCode})`,
        );
      } catch (err) {
        const errorMessage = err instanceof Error ? err.message : String(err);
        this.deliveries.push({
          id: deliveryId,
          webhookId: registration.id,
          url: registration.url,
          eventType,
          payload,
          status: 'failure',
          error: errorMessage,
          deliveredAt: new Date(),
        });
        this.logger.info(
          `Webhook delivery failed: ${deliveryId} to ${registration.url} — ${errorMessage}`,
        );
      }
    }
  }

  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }

  clearRegistrations(): void {
    this.registrations = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-handler.js';
import type { WebhookHttpClient, WebhookPayload } from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;
  let mockHttpClient: WebhookHttpClient;
  let httpCalls: Array<{ url: string; payload: WebhookPayload; secret?: string }>;

  beforeEach(() => {
    eventBus = new EventBus();
    httpCalls = [];
    mockHttpClient = vi.fn(async (url, payload, secret?) => {
      httpCalls.push({ url, payload, secret });
      return { statusCode: 200 };
    });
    handler = new WebhookHandler(eventBus, mockHttpClient);
    resetWebhookIdCounters();
  });

  const createdEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
      ],
      total: 45,
      status: 'pending',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-01T12:00:00Z'),
  };

  function makeStatusEvent(
    previousStatus: string,
    newStatus: string,
  ): OrderStatusChangedEvent {
    return {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date('2026-01-01T13:00:00Z'),
    };
  }

  describe('webhook registration', () => {
    it('should register a webhook and return registration object', () => {
      const reg = handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventTypes).toEqual(['order:created']);
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should register with a secret', () => {
      const reg = handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      expect(reg.secret).toBe('my-secret');
    });

    it('should register for multiple event types', () => {
      const reg = handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      expect(reg.eventTypes).toEqual(['order:created', 'order:status-changed']);
    });

    it('should list all registrations', () => {
      handler.register({ url: 'https://a.com/hook', eventTypes: ['order:created'] });
      handler.register({ url: 'https://b.com/hook', eventTypes: ['order:status-changed'] });

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.unregister(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering unknown ID', () => {
      expect(handler.unregister('nonexistent')).toBe(false);
    });
  });

  describe('order:created webhooks', () => {
    it('should dispatch webhook on order created event', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      expect(httpCalls).toHaveLength(1);
      expect(httpCalls[0]?.url).toBe('https://example.com/hook');
      expect(httpCalls[0]?.payload.event).toBe('order:created');
      expect(httpCalls[0]?.payload.data).toEqual({
        orderId: 'order-1',
        userId: 'user-1',
        items: createdEvent.order.items,
        total: 45,
        status: 'pending',
      });
    });

    it('should include ISO timestamp in payload', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      expect(httpCalls[0]?.payload.timestamp).toBe('2026-01-01T12:00:00.000Z');
    });

    it('should pass secret to http client', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      await eventBus.emit(createdEvent);

      expect(httpCalls[0]?.secret).toBe('my-secret');
    });
  });

  describe('order:status-changed webhooks', () => {
    it('should dispatch webhook on status change event', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(httpCalls).toHaveLength(1);
      expect(httpCalls[0]?.payload.event).toBe('order:status-changed');
      expect(httpCalls[0]?.payload.data).toEqual({
        orderId: 'order-1',
        userId: 'user-1',
        previousStatus: 'pending',
        newStatus: 'confirmed',
      });
    });

    it('should not dispatch to webhooks registered for other event types', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(httpCalls).toHaveLength(0);
    });
  });

  describe('dispatch to multiple webhooks', () => {
    it('should dispatch to all matching registrations', async () => {
      handler.register({ url: 'https://a.com/hook', eventTypes: ['order:created'] });
      handler.register({ url: 'https://b.com/hook', eventTypes: ['order:created'] });

      await eventBus.emit(createdEvent);

      expect(httpCalls).toHaveLength(2);
      expect(httpCalls[0]?.url).toBe('https://a.com/hook');
      expect(httpCalls[1]?.url).toBe('https://b.com/hook');
    });

    it('should dispatch to webhook registered for multiple event types', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(createdEvent);
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(httpCalls).toHaveLength(2);
      expect(httpCalls[0]?.payload.event).toBe('order:created');
      expect(httpCalls[1]?.payload.event).toBe('order:status-changed');
    });

    it('should not dispatch when no webhooks are registered', async () => {
      await eventBus.emit(createdEvent);

      expect(httpCalls).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('delivery tracking', () => {
    it('should track successful deliveries', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
    });

    it('should track failed deliveries from non-2xx status', async () => {
      const failClient: WebhookHttpClient = async () => ({ statusCode: 500 });
      const failHandler = new WebhookHandler(eventBus, failClient);
      failHandler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      const deliveries = failHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should track failed deliveries from network errors', async () => {
      const errorClient: WebhookHttpClient = async () => {
        throw new Error('Connection refused');
      };
      const errorHandler = new WebhookHandler(eventBus, errorClient);
      errorHandler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      const deliveries = errorHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
      expect(deliveries[0]?.error).toBe('Connection refused');
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.register({ url: 'https://a.com/hook', eventTypes: ['order:created'] });
      handler.register({ url: 'https://b.com/hook', eventTypes: ['order:created'] });

      await eventBus.emit(createdEvent);

      const deliveries = handler.getDeliveriesForWebhook(reg1.id);
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://a.com/hook');
    });

    it('should count deliveries', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(createdEvent);
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should clear deliveries', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);
      handler.clearDeliveries();

      expect(handler.getDeliveryCount()).toBe(0);
    });

    it('should generate sequential delivery IDs', async () => {
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(createdEvent);
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[1]?.id).toBe('delivery-0002');
    });
  });

  describe('integration with EventBus', () => {
    it('should coexist with NotificationService and EmailNotificationHandler', async () => {
      const { NotificationService } = await import(
        '../../src/services/notification.service.js'
      );
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email-handler.js'
      );

      const notifService = new NotificationService(eventBus);
      const emailHandler = new EmailNotificationHandler(eventBus);
      handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(createdEvent);

      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
      expect(handler.getDeliveryCount()).toBe(1);
    });

    it('should not dispatch after unregistering', async () => {
      const reg = handler.register({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      handler.unregister(reg.id);
      await eventBus.emit(createdEvent);

      expect(httpCalls).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });
});

