/**
 * Default HTTP client using dynamic import of Node's http/https modules.
 * In production, callers should inject their own HTTP client.
 */
const defaultHttpClient: WebhookHttpClient = async (url, payload, _secret?) => {
  return new Promise<{ statusCode: number }>((resolve, reject) => {
    const urlObj = new URL(url);
    const data = JSON.stringify(payload);
    const mod = urlObj.protocol === 'https:' ? 'https' : 'http';

    import(mod).then(({ request }) => {
      const req = request(
        url,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(data),
          },
        },
        (res: { statusCode: number }) => {
          resolve({ statusCode: res.statusCode });
        },
      );
      req.on('error', reject);
      req.write(data);
      req.end();
    }).catch(reject);
  });
};

